# app.py
from flask import Flask, render_template, request
from flask_socketio import SocketIO, emit, join_room, leave_room

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret!' # Flask-SocketIO için gerekli
socketio = SocketIO(app)

@app.route('/')
def index():
    return render_template('index.html')

@socketio.on('connect')
def handle_connect():
    print(f'Client connected: {request.sid}')
    emit('my_response', {'data': 'Connected to server!'})

@socketio.on('disconnect')
def handle_disconnect():
    print(f'Client disconnected: {request.sid}')

@socketio.on('my_event')
def handle_my_event(json_data):
    """
    Bu, istemciden 'my_event' adıyla bir mesaj alındığında tetiklenen real-time endpoint'tir.
    Alınan veriyi işler ve istemciye geri yanıt gönderir.
    """
    print(f'Received my_event from {request.sid}: {json_data}')
    # Yalnızca mesajı gönderen istemciye geri yanıt gönder
    emit('my_response', {'data': f"Server received: '{json_data['message']}' and responded."})

@socketio.on('join')
def on_join(data):
    username = data['username']
    room = data['room']
    join_room(room)
    print(f'{username} joined room: {room} (SID: {request.sid})')
    emit('my_response', {'data': f'{username} has entered the room {room}.'}, room=room)

@socketio.on('leave')
def on_leave(data):
    username = data['username']
    room = data['room']
    leave_room(room)
    print(f'{username} left room: {room} (SID: {request.sid})')
    emit('my_response', {'data': f'{username} has left the room {room}.'}, room=room)

@socketio.on('broadcast_message')
def handle_broadcast_message(json_data):
    """
    Bu, istemciden 'broadcast_message' adıyla bir mesaj alındığında tetiklenir.
    Mesajı tüm bağlı istemcilere (gönderen dahil) yayınlar.
    """
    print(f'Received broadcast_message from {request.sid}: {json_data}')
    emit('my_response', {'data': f"BROADCAST from {request.sid}: '{json_data['message']}'"}, broadcast=True)

if __name__ == '__main__':
    socketio.run(app, debug=True, allow_unsafe_werkzeug=True)

