<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Flask-SocketIO Realtime Example</title>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/socket.io/4.0.1/socket.io.js"></script>
    <style>
        body { font-family: sans-serif; margin: 20px; background-color: #f4f4f4; color: #333; }
        h1 { color: #0056b3; }
        div { margin-bottom: 15px; padding: 10px; border: 1px solid #ddd; background-color: #fff; border-radius: 5px; }
        input[type="text"], button { padding: 8px; margin: 5px 0; border: 1px solid #ccc; border-radius: 4px; }
        button { cursor: pointer; background-color: #007bff; color: white; border: none; }
        button:hover { background-color: #0056b3; }
        #log { border: 1px solid #ccc; padding: 10px; min-height: 200px; max-height: 400px; overflow-y: auto; background-color: #e9ecef; border-radius: 5px; margin-top: 20px; }
        .log-item { margin-bottom: 5px; color: #555; }
        .log-item.server { color: #007bff; font-weight: bold; }
        .log-item.client { color: #28a745; }
    </style>
</head>
<body>
    <h1>Flask-SocketIO Real-time Endpoint</h1>

    <div>
        <h2>Send Private Message</h2>
        <input type="text" id="private_message_input" placeholder="Enter your message">
        <button onclick="sendPrivateMessage()">Send to Server</button>
    </div>

    <div>
        <h2>Join/Leave Room</h2>
        <input type="text" id="username_input" placeholder="Your username (e.g., Alice)">
        <input type="text" id="room_input" placeholder="Room name (e.g., ChatRoom1)">
        <button onclick="joinRoom()">Join Room</button>
        <button onclick="leaveRoom()">Leave Room</button>
    </div>

    <div>
        <h2>Broadcast Message to All</h2>
        <input type="text" id="broadcast_message_input" placeholder="Message to broadcast">
        <button onclick="sendBroadcastMessage()">Broadcast</button>
    </div>

    <h2>Activity Log:</h2>
    <div id="log"></div>

    <script type="text/javascript">
        var socket = io();

        socket.on('connect', function() {
            logMessage('Connected to server!', 'server');
        });

        socket.on('disconnect', function() {
            logMessage('Disconnected from server!', 'server');
        });

        // Sunucudan gelen genel yanıtları dinle
        socket.on('my_response', function(msg) {
            logMessage('Server: ' + msg.data, 'server');
        });

        function sendPrivateMessage() {
            var message = document.getElementById('private_message_input').value;
            if (message) {
                socket.emit('my_event', { message: message });
                logMessage('Client: Sent private message "' + message + '"', 'client');
                document.getElementById('private_message_input').value = '';
            }
        }

        function joinRoom() {
            var username = document.getElementById('username_input').value;
            var room = document.getElementById('room_input').value;
            if (username && room) {
                socket.emit('join', { username: username, room: room });
                logMessage('Client: Attempting to join room "' + room + '" as "' + username + '"', 'client');
            } else {
                alert("Please enter both username and room name.");
            }
        }

        function leaveRoom() {
            var username = document.getElementById('username_input').value;
            var room = document.getElementById('room_input').value;
            if (username && room) {
                socket.emit('leave', { username: username, room: room });
                logMessage('Client: Attempting to leave room "' + room + '" as "' + username + '"', 'client');
            } else {
                alert("Please enter both username and room name.");
            }
        }

        function sendBroadcastMessage() {
            var message = document.getElementById('broadcast_message_input').value;
            if (message) {
                socket.emit('broadcast_message', { message: message });
                logMessage('Client: Sent broadcast message "' + message + '"', 'client');
                document.getElementById('broadcast_message_input').value = '';
            }
        }

        function logMessage(msg, type = 'general') {
            var logDiv = document.getElementById('log');
            var p = document.createElement('p');
            p.className = 'log-item ' + type;
            p.textContent = '[' + new Date().toLocaleTimeString() + '] ' + msg;
            logDiv.appendChild(p);
            logDiv.scrollTop = logDiv.scrollHeight; // Scroll to bottom
        }
    </script>
</body>
</html>
